#include <stdio.h>
#include <string.h>

int isVowel(char c) {
    return c=='a' || c=='e' || c=='i' || c=='o' || c=='u';
}

int main() {
    int T; 
    if (scanf("%d", &T)!=1) return 0;
    char s[1005];
    while (T--) {
        scanf("%s", s);
        int cnt = 0;
        int happy = 0;
        for (int i = 0; s[i]; ++i) {
            if (isVowel(s[i])) {
                cnt++;
                if (cnt > 2) { happy = 1; break; }
            } else {
                cnt = 0;
            }
        }
        printf(happy ? "HAPPY\n" : "SAD\n");
    }
    return 0;
}

